import{_ as e,o as a,c as l,a4 as o}from"./chunks/framework.BMymQDdR.js";const k=JSON.parse('{"title":"环境安装","description":"","frontmatter":{},"headers":[],"relativePath":"course/install-env.md","filePath":"zh/course/install-env.md","lastUpdated":1735888139000}'),t={name:"course/install-env.md"},i=o(`<h1 id="环境安装" tabindex="-1">环境安装 <a class="header-anchor" href="#环境安装" aria-label="Permalink to &quot;环境安装&quot;">​</a></h1><p>视频教程</p><ul><li><a href="https://www.bilibili.com/video/BV1MN411Q7a2/" target="_blank" rel="noreferrer">开发环境安装</a></li><li><a href="https://www.bilibili.com/video/BV1gv6mYdE5J/" target="_blank" rel="noreferrer">应用创建、构建、安装包制作</a></li></ul><h2 id="开发环境依赖" tabindex="-1">开发环境依赖 <a class="header-anchor" href="#开发环境依赖" aria-label="Permalink to &quot;开发环境依赖&quot;">​</a></h2><p>开发环境依赖Golang和CEF构建好的二进制框架。 如果开发完到生产包后，此时除了Golang编译好的二进制执行程序，同时CEF和liblcl一起打包。</p><p>下面列表是开发环境安装选项</p><table tabindex="0"><thead><tr><th>名称</th><th>平台</th><th>是否必须</th><th>说明</th></tr></thead><tbody><tr><td>Golang</td><td>ALL</td><td>是</td><td>Go语言开发环境</td></tr><tr><td>CEF, LibLCL</td><td>ALL</td><td>是</td><td>CEF框架</td></tr><tr><td>NSIS</td><td>Windows</td><td>否</td><td>Windows安装包制作工具</td></tr><tr><td>UPX</td><td>ALL</td><td>否</td><td>执行文件压缩工具</td></tr><tr><td>7z</td><td>Windows, Linux</td><td>否</td><td>CEF框架压缩工具</td></tr></tbody></table><h2 id="开发环境安装的3种方式" tabindex="-1">开发环境安装的3种方式 <a class="header-anchor" href="#开发环境安装的3种方式" aria-label="Permalink to &quot;开发环境安装的3种方式&quot;">​</a></h2><h3 id="_1、自动安装完整开发环境-在线-推荐" tabindex="-1">1、自动安装完整开发环境 - <span style="color:#2ba9f1;">在线 推荐</span> <a class="header-anchor" href="#_1、自动安装完整开发环境-在线-推荐" aria-label="Permalink to &quot;1、自动安装完整开发环境 - &lt;span style=&quot;color: #2ba9f1;&quot;&gt;在线 推荐&lt;/span&gt;&quot;">​</a></h3><h4 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h4><p>使用energy命令行工具安装开发环境, 它通过网络下载CEF和liblcl, CEF二进制包在CEF官方构建仓库, 因此存在下载失败可能, 如果失败请参考离线安装.</p><h4 id="获取-energy-cli-命令行工具" tabindex="-1">获取 energy cli 命令行工具 <a class="header-anchor" href="#获取-energy-cli-命令行工具" aria-label="Permalink to &quot;获取 energy cli 命令行工具&quot;">​</a></h4><ul><li>获取方式 一 预编译命令行工具 <a href="/course/cli-download">下载 CLI</a></li></ul><blockquote><p>该方式可跳过方式二</p></blockquote><ul><li>获取方式 二 自行编译命令行工具</li></ul><blockquote><p>需要你自己安装<a href="https://golang.google.cn/dl/" target="_blank" rel="noreferrer">Golang</a>环境</p><blockquote><ol><li>克隆项目 <code>git clone https://github.com/energye/energy.git</code></li><li>下载依赖 <code>go mod tidy</code></li><li>进入 energy/cmd/energy 目录 <code>cd energy/cmd/energy</code></li></ol><p>执行命令 &quot;go install&quot; 安装命令行工具</p><p><code>go install</code></p></blockquote></blockquote><h4 id="安装开发环境" tabindex="-1">安装开发环境 <a class="header-anchor" href="#安装开发环境" aria-label="Permalink to &quot;安装开发环境&quot;">​</a></h4><p>执行命令</p><ol><li>在此前初始化环境</li></ol><p><code>energy env</code> 查看环境, 会显示类似下面的列表</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">┌───────────────────────────────────────┐</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name      | Value                     |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-------------------------------------</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Golang    |                           |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Root      | /Users/yanghy             |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Framework |                           |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| NSIS      |                           |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 7z        |                           |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| UPX       |                           |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Registry  | https://energye.github.io |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Proxy     |                           |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">└───────────────────────────────────────┘</span></span></code></pre></div><p><code>energy env -w root:/Users/yanghy/app</code> 修改 framework 安装根目录, <code>root:替换成你的目录</code></p><ol start="2"><li>执行安装命令</li></ol><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">energy install</span></span></code></pre></div><p>直接在（windows -&gt; cmd）(linux or macosx -&gt; terminal) 中执行</p><blockquote><p>linux 需要安装 gtk, 默认 energy 依赖是GTK3.</p></blockquote><p>安装命令</p><ul><li>GTK3 <code>sudo apt-get install libgtk-3-dev</code></li><li>GTK2 <code>sudo apt-get install libgtk2.0-dev</code></li><li>OPENGL <code>sudo apt-get install libharfbuzz-gobject0</code></li></ul><p><a href="/course/">关于 energy cli 使用</a></p><hr><h3 id="_2、自动安装开发环境-离线" tabindex="-1">2、自动安装开发环境 - <span style="color:#2ba9f1;">离线</span> <a class="header-anchor" href="#_2、自动安装开发环境-离线" aria-label="Permalink to &quot;2、自动安装开发环境 - &lt;span style=&quot;color: #2ba9f1;&quot;&gt;离线&lt;/span&gt;&quot;">​</a></h3><h4 id="说明-1" tabindex="-1">说明 <a class="header-anchor" href="#说明-1" aria-label="Permalink to &quot;说明&quot;">​</a></h4><blockquote><p>提供给无网络或在线安装下载失败的用户</p></blockquote><h4 id="工具获取" tabindex="-1">工具获取 <a class="header-anchor" href="#工具获取" aria-label="Permalink to &quot;工具获取&quot;">​</a></h4><blockquote><p>参考: <span style="color:#2ba9f1;">方式1-在线安装</span> 使用 energy cli 自动安装配置开发环境，适用: Window、Linux、MacOS</p></blockquote><h4 id="手动下载二进制框架" tabindex="-1">手动下载二进制框架 <a class="header-anchor" href="#手动下载二进制框架" aria-label="Permalink to &quot;手动下载二进制框架&quot;">​</a></h4><blockquote><p>获取CEF和对应LibLCL动态库 <a href="/course/download-version">下载链接</a></p><ol><li>在你希望安装的位置, 例如: <code>/app</code> , 在 <code>/app</code> 新建目录名为 <code>energy</code> 和 <code>EnergyFrameworkDownloadCache</code></li><li>修改环境-安装根目录: <code>energy env -w root:/app</code></li><li>将下载的 CEF 和 LibLCL 对应压缩包移动到 <code>EnergyFrameworkDownloadCache</code> 目录</li><li>安装</li></ol><blockquote><p><code>energy install</code> 注意: 如果不是最新版本, 例如带有版本号的 liblcl-109.xxx.zip <code>energy install --cef 109</code></p></blockquote></blockquote><hr><h3 id="_3、手动安装开发环境" tabindex="-1">3、手动安装开发环境 <a class="header-anchor" href="#_3、手动安装开发环境" aria-label="Permalink to &quot;3、手动安装开发环境&quot;">​</a></h3><h4 id="说明和准备" tabindex="-1">说明和准备 <a class="header-anchor" href="#说明和准备" aria-label="Permalink to &quot;说明和准备&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>该方式完全手动安装开发环境，把 cli 安装开发环境做的事情我们用手动操作一遍</span></span>
<span class="line"><span>获取 CEF 和 LibLCL</span></span>
<span class="line"><span>CEF 压缩包</span></span>
<span class="line"><span>   1. Windows和Linux只用到CEF的Release和Resources目录内的文件</span></span>
<span class="line"><span>   2. MacOSX只用到了Release目录内文件</span></span>
<span class="line"><span>LibLCL 压缩包</span></span>
<span class="line"><span>   liblcl.xx 文件</span></span>
<span class="line"><span>.energy 环境配置</span></span>
<span class="line"><span>   使用 energy env 命令修改环境参数</span></span>
<span class="line"><span>   \`energy env -w root:/framework/root/path 修改框架安装根目录</span></span></code></pre></div><h4 id="开始" tabindex="-1">开始 <a class="header-anchor" href="#开始" aria-label="Permalink to &quot;开始&quot;">​</a></h4><blockquote><p><a href="/course/download-version">CEF 和 LibLCL 版本下载</a></p><ol><li>下载好后，例如是<code>CEF 109 Windows64</code>版本. 在你希望安装的位置, 例如: <code>D:/app</code> , 在 <code>D:/app</code> 新建目录名为 <code>energy</code></li><li>进入 <code>energy</code> 目录, 新建 framework 目录 <code>CEF-109_WINDOWS_64</code>, 规则: <code>CEF-[VER]_[OS]_[ARCH]</code></li><li>将下载的 <code>cef_xxx.tar.bz2</code> 压缩包中提取<code>Release</code>和<code>Resources</code>目录<code>内</code>文件到<code>CEF-109_WINDOWS_64</code>文件夹</li><li>将下载的 <code>liblcl-xx.[OS][ARCH].zip</code> 内容提取到 <code>CEF-109_WINDOWS_64</code>文件夹</li><li>配置环境-框架根目录: <code>energy env -w root:D:/app</code></li><li>配置环境-框架版本: <code>energy env -w framework:CEF-109_WINDOWS_64</code></li></ol></blockquote><blockquote><blockquote><p>最终 CEF-109_WINDOWS_64 目录结构</p><blockquote><p>locales - 文件夹</p><p>cef_sandbox.lib - 文件</p><p>chrome_100_percent.pak - 文件</p><p>chrome_200_percent.pak - 文件</p><p>chrome_elf.dll - 文件</p><p>d3dcompiler_47.dll - 文件</p><p>icudtl.dat - 文件</p><p>libcef.dll - 文件</p><p>libcef.lib - 文件</p><p>libEGL.dll - 文件</p><p>libGLESv2.dll - 文件</p><p>liblcl.dll - 文件</p><p>resources.pak - 文件</p><p>snapshot_blob.bin - 文件</p><p>v8_context_snapshot.bin - 文件</p><p>vk_swiftshader.dll - 文件</p><p>vk_swiftshader_icd.json - 文件</p><p>vulkan-1.dll - 文件</p></blockquote></blockquote></blockquote><h4 id="macos-x" tabindex="-1">MacOS X <a class="header-anchor" href="#macos-x" aria-label="Permalink to &quot;MacOS X&quot;">​</a></h4><blockquote><p><a href="/course/download-version">CEF 和 LibLCL 版本下载</a></p><p>和 Windows 步骤完全一样</p><p>不同的是提取 CEF 文件稍有不同, 和 framework 目录名不同 <code>CEF-109_DARWIN_64</code></p><blockquote><p>只提取 Release 到 <code>CEF-109_DARWIN_64</code></p><p>最终 CEF-109_DARWIN_64 目录结构</p><blockquote><p>Chromium Embedded Framework.framework - 文件夹</p><p>cef_sandbox.a - 文件</p><p>liblcl.dylib - 文件</p></blockquote></blockquote></blockquote><h5 id="mac-m系列" tabindex="-1">Mac M系列 <a class="header-anchor" href="#mac-m系列" aria-label="Permalink to &quot;Mac M系列&quot;">​</a></h5><blockquote><p>对于 Mac ARM架构, 开发环境和 Mac x86 一样</p><p>可使用 x86 架构包兼容运行，也可使用 ARM 专有架构</p><p>在Mac ARM Go需要使用交叉编译, 设置Go的编译环境为 amd64, 和CGO支持 通过 Rosetta2 兼容运行AMD架构应用 需要额外安装</p><ol><li>GCC工具链 <code>brew install gcc</code>, 还可能需要安装<code>xcode-select --install</code></li><li>Rosetta2 <a href="https://support.apple.com/zh-cn/HT211861" target="_blank" rel="noreferrer">参考链接</a></li></ol><p>编译环境设置</p><ul><li>交叉环境: <code>GOARCH=amd64</code></li><li>开启CGO: <code>CGO_ENABLED=1</code></li></ul></blockquote><h2 id="其它依赖" tabindex="-1">其它依赖 <a class="header-anchor" href="#其它依赖" aria-label="Permalink to &quot;其它依赖&quot;">​</a></h2><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><blockquote><p>Linux 需要额外安装一些共享支持库</p></blockquote><p>安装命令</p><ul><li>GTK3 <code>sudo apt-get install libgtk-3-dev</code></li><li>GTK2 <code>sudo apt-get install libgtk2.0-dev</code></li><li>OPENGL <code>sudo apt-get install libharfbuzz-gobject0</code></li></ul><h3 id="环境配置" tabindex="-1">环境配置 <a class="header-anchor" href="#环境配置" aria-label="Permalink to &quot;环境配置&quot;">​</a></h3><blockquote><p><a href="/course/download-version">CEF 和 LibLCL 版本下载</a></p><p>和 Windows 步骤完全一样 不同，使用 Linux 版本即可</p></blockquote><h3 id="环境安装失败" tabindex="-1">环境安装失败 <a class="header-anchor" href="#环境安装失败" aria-label="Permalink to &quot;环境安装失败&quot;">​</a></h3><p>在线安装，由于网络因素或其它限制，获取远程服务资源时可能会失败, 导致开发环境安装失败。</p><p>配置 proxy: <code>energy env -w proxy:http://ip:port</code></p>`,58),s=[i];function n(d,c,p,r,h,b){return a(),l("div",null,s)}const g=e(t,[["render",n]]);export{k as __pageData,g as default};
